import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [role, setRole] = useState(null);
  const [students, setStudents] = useState([]);
  const [selectedFasal, setSelectedFasal] = useState("Dhamaan");
  const [currentUser, setCurrentUser] = useState(null);
  const [newS, setNewS] = useState({ magaca: "", fasalka: "Fasalka 1" });

  useEffect(() => {
    if (role === 'admin') loadStudents();
  }, [role]);

  const loadStudents = () => {
    axios.get('http://localhost:3000/admin/students').then(res => setStudents(res.data));
  };

  const updateStudent = (id, field, value) => {
    axios.put(`http://localhost:3000/admin/update-student/${id}`, { [field]: value })
      .then(() => loadStudents());
  };

  const handleAdd = () => {
    axios.post('http://localhost:3000/students/add', newS).then(() => loadStudents());
  };

  const filtered = students.filter(s => selectedFasal === "Dhamaan" ? true : s.fasalka === selectedFasal);

  const AdminView = () => (
    <div style={{ padding: '20px' }}>
      <div style={{display: 'flex', justifyContent: 'space-between'}}>
        <h2>💻 Maamulka Imtixaanka & Lacagaha</h2>
        <button onClick={() => {
            const p = prompt("Geli Password-ka cusub:");
            if(p) axios.post('http://localhost:3000/admin/change-password', { newPassword: p });
        }} style={{background: '#f39c12', color: 'white', border: 'none', padding: '10px', borderRadius: '5px'}}>Beddel Password-ka Admin</button>
      </div>

      {/* FORM-KA ADD STUDENT */}
      <div style={{background: '#fff', padding: '20px', borderRadius: '10px', margin: '20px 0', border: '1px solid #ddd'}}>
        <input type="text" placeholder="Magaca" style={{padding: '8px', marginRight: '10px'}} onChange={e => setNewS({...newS, magaca: e.target.value})} />
        <select onChange={e => setNewS({...newS, fasalka: e.target.value})} style={{padding: '8px', marginRight: '10px'}}>
            {["Fasalka 1", "Fasalka 2", "Fasalka 3", "Fasalka 4", "Fasalka 5", "Fasalka 6", "Fasalka 7", "Fasalka 8", "Form 1", "Form 2", "Form 3", "Form 4"].map(f => <option value={f}>{f}</option>)}
        </select>
        <button onClick={handleAdd} style={{background: '#1a73e8', color: 'white', padding: '8px 20px', border: 'none', borderRadius: '5px'}}>Add Student</button>
      </div>

      <select onChange={e => setSelectedFasal(e.target.value)} style={{padding: '10px', marginBottom: '20px', width: '250px'}}>
        <option value="Dhamaan">Dhamaan (120 Arday)</option>
        {["Fasalka 1", "Fasalka 2", "Fasalka 3", "Fasalka 4", "Fasalka 5", "Fasalka 6", "Fasalka 7", "Fasalka 8", "Form 1", "Form 2", "Form 3", "Form 4"].map(f => <option value={f}>{f}</option>)}
      </select>

      <table border="1" width="100%" style={{ borderCollapse: 'collapse', background: 'white' }}>
        <thead style={{ background: '#2c3e50', color: 'white' }}>
          <tr>
            <th>ID</th>
            <th>Magaca</th>
            <th>Fasalka</th>
            <th>Lacagta (Edit)</th>
            <th>Dhibcaha (Edit)</th>
            <th>Action</th>
          </tr>
        </thead>
        <tbody>
          {filtered.map(s => (
            <tr key={s.id} style={{ textAlign: 'center' }}>
              <td>{s.id}</td>
              <td>{s.magaca}</td>
              <td>{s.fasalka}</td>
              <td>
                <select value={s.lacagta} onChange={(e) => updateStudent(s.id, 'lacagta', e.target.value)}>
                    <option value="Bixiyey">Bixiyey</option>
                    <option value="Ma bixin">Ma bixin</option>
                </select>
              </td>
              <td>
                <input type="number" value={s.dhibcaha} style={{width: '60px', textAlign: 'center'}} 
                  onChange={(e) => updateStudent(s.id, 'dhibcaha', e.target.value)} /> %
              </td>
              <td>
                <button onClick={() => axios.delete(`http://localhost:3000/students/${s.id}`).then(() => loadStudents())} style={{background: '#e74c3c', color: 'white', border: 'none', padding: '5px'}}>Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  if (!role) {
    return (
      <div style={{ textAlign: 'center', marginTop: '100px', fontFamily: 'Arial' }}>
        <h1>Dugsi Management System</h1>
        <div style={{ display: 'flex', justifyContent: 'center', gap: '20px', marginTop: '40px' }}>
          <button style={btnStyle} onClick={() => {
            const p = prompt("Geli Admin Password:");
            axios.post('http://localhost:3000/login', { type: 'admin', password: p })
              .then(() => setRole('admin')).catch(() => alert("Password-ka waa khalad!"));
          }}>Geli Maamule</button>

          <button style={btnStyle} onClick={() => {
            const id = prompt("Geli ID (S0101 - S1210):");
            const p = prompt("Geli Password (123):");
            axios.post('http://localhost:3000/login', { type: 'student', id, password: p })
              .then(res => { setCurrentUser(res.data); setRole('student'); })
              .catch(() => alert("Aqoonsi khaldan!"));
          }}>Geli Arday</button>
        </div>
      </div>
    );
  }

  return (
    <div style={{ backgroundColor: '#f0f5f3ff', minHeight: '100vh', fontFamily: 'Arial' }}>
      <div style={{background: '#2c3e50', padding: '15px'}}><button onClick={() => setRole(null)} style={{background: '#e74c3c', color: 'white', border: 'none', padding: '8px 15px', cursor: 'pointer', borderRadius: '5px'}}>Logout</button></div>
      {role === 'admin' ? <AdminView /> : (
        <div style={{padding: '50px', textAlign: 'center'}}>
            <h2>Ku soo dhawaaw, {currentUser.magaca}</h2>
            <div style={{display: 'inline-block', background: 'white', padding: '40px', borderRadius: '20px', boxShadow: '0 5px 15px rgba(0,0,0,0.1)'}}>
                <h3>Fasalkaaga: <span style={{color: '#1a73e8'}}>{currentUser.fasalka}</span></h3>
                <hr/>
                <h3>Natiijada Imtixaanka: <span style={{color: '#27ae60'}}>{currentUser.dhibcaha}%</span></h3>
                <h3>Xaaladda Lacagta: <span style={{color: currentUser.lacagta === 'Bixiyey' ? 'green' : 'red'}}>{currentUser.lacagta}</span></h3>
                <p style={{marginTop: '20px', color: '#888', fontStyle: 'italic'}}>* Ardaygu waxba ma beddeli karo, kaliya xogta fiiri.</p>
            </div>
        </div>
      )}
    </div>
  );
}

const btnStyle = { padding: '25px 40px', fontSize: '18px', cursor: 'pointer', borderRadius: '12px', border: 'none', background: '#1a73e8', color: 'white' };
export default App;
